#include <stdio.h>
#include <string.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[301];
        scanf("%s", S);
        int len = strlen(S);
        long long pos = 0;
        int i = 1;
        while (1) {
            char temp[301];
            sprintf(temp, "%d", i);
            int len2 = strlen(temp);
            if (pos + len2 > pos + len) {
                char D[1000000];
                int idx = 0;
                for (int j = 1; j <= i; j++) {
                    char temp2[301];
                    sprintf(temp2, "%d", j);
                    strcat(D, temp2);
                }
                if (strstr(D, S) != NULL) {
                    char *ptr = strstr(D, S);
                    int pos2 = ptr - D + 1;
                    printf("%lld\n", pos2 % MOD);
                    break;
                }
            }
            pos += len2;
            i++;
        }
    }
    return 0;
}

