import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String S = sc.next();
            int len = S.length();
            long pos = 0;
            int i = 1;
            while (true) {
                String temp = Integer.toString(i);
                int len2 = temp.length();
                if (pos + len2 > pos + len) {
                    StringBuilder D = new StringBuilder();
                    for (int j = 1; j <= i; j++) {
                        D.append(Integer.toString(j));
                    }
                    if (D.toString().contains(S)) {
                        int pos2 = D.toString().indexOf(S) + 1;
                        System.out.println(pos2 % 1000000007);
                        break;
                    }
                }
                pos += len2;
                i++;
            }
        }
    }
}

